import SwiftUI
import Combine

// MARK: - Models

struct Stock: Identifiable, Codable {
    let id: String
    let symbol: String
    var name: String
    var price: Double
    var quantity: Int
}

struct TradeResponse: Codable {
    let success: Bool
    let message: String
    let updatedPortfolio: [Stock]
}

// MARK: - Services

class StockDataService: ObservableObject {
    @Published var stocks: [Stock] = []
    private var cancellables = Set<AnyCancellable>()
    
    func fetchStocks() {
        guard let url = URL(string: "https://api.securebrokerage.com/stocks/realtime") else { return }
        var request = URLRequest(url: url)
        request.httpMethod = "GET"
        let session = createSecureSession()
        
        session.dataTaskPublisher(for: request)
            .map { $0.data }
            .decode(type: [Stock].self, decoder: JSONDecoder())
            .receive(on: DispatchQueue.main)
            .sink(receiveCompletion: { _ in }, receiveValue: { [weak self] fetchedStocks in
                self?.stocks = fetchedStocks
            })
            .store(in: &cancellables)
    }
    
    private func createSecureSession() -> URLSession {
        let config = URLSessionConfiguration.ephemeral
        config.waitsForConnectivity = true
        return URLSession(configuration: config)
    }
}

class TradingService: ObservableObject {
    func executeTrade(stock: Stock, quantity: Int, isBuy: Bool, completion: @escaping (Result<[Stock], Error>) -> Void) {
        guard let url = URL(string: "https://api.securebrokerage.com/trade/execute") else { return }
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let tradePayload: [String: Any] = [
            "symbol": stock.symbol,
            "quantity": quantity,
            "isBuy": isBuy
        ]
        
        request.httpBody = try? JSONSerialization.data(withJSONObject: tradePayload, options: [])
        let session = URLSession.shared
        
        session.dataTask(with: request) { data, _, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            guard let data = data,
                  let response = try? JSONDecoder().decode(TradeResponse.self, from: data),
                  response.success else {
                completion(.failure(NSError(domain: "", code: -1, userInfo: nil)))
                return
            }
            completion(.success(response.updatedPortfolio))
        }.resume()
    }
}

// MARK: - ViewModels

class PortfolioViewModel: ObservableObject {
    @Published var portfolio: [Stock] = []
    private let tradingService: TradingService
    
    init(tradingService: TradingService) {
        self.tradingService = tradingService
    }
    
    func updatePortfolio(_ newPortfolio: [Stock]) {
        DispatchQueue.main.async {
            self.portfolio = newPortfolio
        }
    }
    
    func executeTrade(stock: Stock, quantity: Int, isBuy: Bool) {
        tradingService.executeTrade(stock: stock, quantity: quantity, isBuy: isBuy) { [weak self] result in
            switch result {
            case .success(let updatedPortfolio):
                self?.updatePortfolio(updatedPortfolio)
            case .failure:
                break
            }
        }
    }
}

// MARK: - Views

struct ContentView: View {
    @StateObject private var stockData = StockDataService()
    @StateObject private var portfolioVM = PortfolioViewModel(tradingService: TradingService())
    
    var body: some View {
        NavigationView {
            List {
                Section(header: Text("Stocks")) {
                    ForEach(stockData.stocks) { stock in
                        HStack {
                            VStack(alignment: .leading) {
                                Text(stock.symbol).font(.headline)
                                Text(stock.name).font(.subheadline)
                            }
                            Spacer()
                            Text("\(stock.price, specifier: "%.2f")")
                        }
                    }
                }
                
                Section(header: Text("Portfolio")) {
                    ForEach(portfolioVM.portfolio) { holding in
                        HStack {
                            Text(holding.symbol).font(.headline)
                            Spacer()
                            Text("Qty: \(holding.quantity)")
                        }
                    }
                }
            }
            .navigationTitle("Trading App")
            .toolbar {
                ToolbarItem(placement: .navigationBarTrailing) {
                    Button("Refresh") {
                        stockData.fetchStocks()
                    }
                }
            }
        }
        .onAppear {
            stockData.fetchStocks()
        }
    }
}

// MARK: - App

@main
struct TradingApp: App {
    var body: some Scene {
        WindowGroup {
            ContentView()
        }
    }
}